mapper.select:
SELECT COALESCE(SUM(amount), 0)
FROM record
WHERE user_id = #{userId}
  AND type = #{type}
  AND deleted = 0
  AND create_time BETWEEN #{startDate} AND #{endDate}

SELECT
    category,
    COALESCE(SUM(amount), 0) as total_amount
FROM record
WHERE user_id = #{userId}
  AND type = #{type}
  AND deleted = 0
  AND create_time BETWEEN #{startDate} AND #{endDate}
GROUP BY category
ORDER BY total_amount DESC
